INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Làm quen với Python - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Làm quen với Python. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Làm quen với Python.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Làm quen với Python")', '[{"input": "", "expected_output": "Làm quen với Python"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Gọi tên chủ đề', 'Nhiệm vụ: in ra mã chủ đề của lesson Làm quen với Python. Học sinh cần quan sát chuỗi yêu cầu và dùng print() để hiển thị đúng nội dung, giữ nguyên chữ thường, dấu gạch ngang và khoảng trắng nếu có. Kết quả cần khớp chính xác: hello-python.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("hello-python")', '[{"input": "", "expected_output": "hello-python"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Thông tin bài học', 'Nhiệm vụ: hiển thị dòng giới thiệu bài học. Học sinh cần dùng print() để in đúng định dạng gồm chữ Bài, số thứ tự và tên lesson Làm quen với Python. Không thêm ký tự khác ở đầu hoặc cuối dòng. Kết quả cần khớp chính xác: Bài 1: Làm quen với Python.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Bài 1: Làm quen với Python")', '[{"input": "", "expected_output": "Bài 1: Làm quen với Python"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Biến chủ đề', 'Nhiệm vụ: tạo một biến lưu tên chủ đề Làm quen với Python, sau đó ghép chuỗi với phần '' - luyện tập'' và in ra màn hình. Học sinh cần luyện cách khai báo biến, nối chuỗi bằng toán tử + và dùng print() để xuất kết quả. Kết quả cần khớp chính xác: Làm quen với Python - luyện tập.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'topic = "Làm quen với Python"\nprint(topic + " - luyện tập")', '[{"input": "", "expected_output": "Làm quen với Python - luyện tập"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Hai dòng kết quả', 'Nhiệm vụ: in kết quả trên 2 dòng riêng biệt. Dòng 1 là tên lesson Làm quen với Python, dòng 2 là trạng thái Hoàn thành. Học sinh nên dùng 2 lệnh print() khác nhau và không gộp chung thành một dòng. Kết quả cần khớp chính xác: Làm quen với Python\nHoàn thành.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'print("Làm quen với Python")\nprint("Hoàn thành")', '[{"input": "", "expected_output": "Làm quen với Python\nHoàn thành"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Thứ tự bài học', 'Nhiệm vụ: tạo biến số nguyên lưu thứ tự của lesson Làm quen với Python, chuyển số đó sang chuỗi khi cần ghép với câu thông báo, rồi in ra màn hình. Học sinh cần chú ý dùng str() khi nối số với chuỗi. Kết quả cần khớp chính xác: Thứ tự lesson: 1.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'lesson_order = 1\nprint("Thứ tự lesson: " + str(lesson_order))', '[{"input": "", "expected_output": "Thứ tự lesson: 1"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Hàm thông điệp', 'Nhiệm vụ: viết một hàm không có tham số để trả về thông điệp học tập của lesson Làm quen với Python, sau đó gọi hàm và in giá trị trả về. Học sinh cần luyện cú pháp def, return và cách gọi hàm trong Python. Kết quả cần khớp chính xác: Sẵn sàng học Làm quen với Python.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'def message():\n    return "Sẵn sàng học Làm quen với Python"\nprint(message())', '[{"input": "", "expected_output": "Sẵn sàng học Làm quen với Python"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Ba bước luyện tập', 'Nhiệm vụ: dùng vòng lặp để in ra 3 bước luyện tập theo thứ tự từ 1 đến 3. Học sinh cần sử dụng range(), biến lặp và str() để tạo từng dòng theo mẫu Bước 1, Bước 2, Bước 3. Kết quả cần khớp chính xác: Bước 1\nBước 2\nBước 3.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'for step in range(1, 4):\n    print("Bước " + str(step))', '[{"input": "", "expected_output": "Bước 1\nBước 2\nBước 3"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Từ điển bài học', 'Nhiệm vụ: tạo một dictionary lưu thông tin lesson gồm tên bài học và số thứ tự, sau đó lấy dữ liệu từ dictionary để in theo định dạng tên: số. Học sinh cần luyện cách tạo dictionary, truy cập giá trị bằng key và chuyển số sang chuỗi khi ghép. Kết quả cần khớp chính xác: Làm quen với Python: 1.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'lesson = {"name": "Làm quen với Python", "order": 1}\nprint(lesson["name"] + ": " + str(lesson["order"]))', '[{"input": "", "expected_output": "Làm quen với Python: 1"}]'::jsonb, 'Cơ bản'),
('Làm quen với Python - Tổng kết thử thách', 'Nhiệm vụ: in phần tổng kết của lesson Làm quen với Python. Dòng đầu là tên lesson, các dòng sau lần lượt thể hiện số lượng challenge Easy, Medium và Hard. Học sinh nên tạo danh sách các dòng tổng kết rồi dùng vòng lặp để in từng dòng. Kết quả cần khớp chính xác: Làm quen với Python\nEasy: 3\nMedium: 3\nHard: 4.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'levels = ["Easy: 3", "Medium: 3", "Hard: 4"]\nprint("Làm quen với Python")\nfor level in levels:\n    print(level)', '[{"input": "", "expected_output": "Làm quen với Python\nEasy: 3\nMedium: 3\nHard: 4"}]'::jsonb, 'Cơ bản');
