INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Biến đầu tiên - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Biến đầu tiên. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Biến đầu tiên.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Biến đầu tiên")', '[{"input": "", "expected_output": "Biến đầu tiên"}]'::jsonb, 'Cơ bản'),
