INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Điều kiện if - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Điều kiện if. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Điều kiện if.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Điều kiện if")', '[{"input": "", "expected_output": "Điều kiện if"}]'::jsonb, 'Cơ bản'),
('Điều kiện if - Gọi tên chủ đề', 'Nhiệm vụ: in ra mã chủ đề của lesson Điều kiện if. Học sinh cần quan sát chuỗi yêu cầu và dùng print() để hiển thị đúng nội dung, giữ nguyên chữ thường, dấu gạch ngang và khoảng trắng nếu có. Kết quả cần khớp chính xác: if-basic.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("if-basic")', '[{"input": "", "expected_output": "if-basic"}]'::jsonb, 'Cơ bản'),
('Điều kiện if - Thông tin bài học', 'Nhiệm vụ: hiển thị dòng giới thiệu bài học. Học sinh cần dùng print() để in đúng định dạng gồm chữ Bài, số thứ tự và tên lesson Điều kiện if. Không thêm ký tự khác ở đầu hoặc cuối dòng. Kết quả cần khớp chính xác: Bài 8: Điều kiện if.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Bài 8: Điều kiện if")', '[{"input": "", "expected_output": "Bài 8: Điều kiện if"}]'::jsonb, 'Cơ bản'),
