('Điều kiện if else - Tổng kết thử thách', 'Nhiệm vụ: in phần tổng kết của lesson Điều kiện if else. Dòng đầu là tên lesson, các dòng sau lần lượt thể hiện số lượng challenge Easy, Medium và Hard. Học sinh nên tạo danh sách các dòng tổng kết rồi dùng vòng lặp để in từng dòng. Kết quả cần khớp chính xác: Điều kiện if else\nEasy: 3\nMedium: 3\nHard: 4.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'levels = ["Easy: 3", "Medium: 3", "Hard: 4"]\nprint("Điều kiện if else")\nfor level in levels:\n    print(level)', '[{"input": "", "expected_output": "Điều kiện if else\nEasy: 3\nMedium: 3\nHard: 4"}]'::jsonb, 'Cơ bản');
INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Nhiều nhánh với elif - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Nhiều nhánh với elif. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Nhiều nhánh với elif.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Nhiều nhánh với elif")', '[{"input": "", "expected_output": "Nhiều nhánh với elif"}]'::jsonb, 'Cơ bản'),
