('Giá trị trả về - Biến chủ đề', 'Nhiệm vụ: tạo một biến lưu tên chủ đề Giá trị trả về, sau đó ghép chuỗi với phần '' - luyện tập'' và in ra màn hình. Học sinh cần luyện cách khai báo biến, nối chuỗi bằng toán tử + và dùng print() để xuất kết quả. Kết quả cần khớp chính xác: Giá trị trả về - luyện tập.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'topic = "Giá trị trả về"\nprint(topic + " - luyện tập")', '[{"input": "", "expected_output": "Giá trị trả về - luyện tập"}]'::jsonb, 'Cơ bản'),
('Giá trị trả về - Hai dòng kết quả', 'Nhiệm vụ: in kết quả trên 2 dòng riêng biệt. Dòng 1 là tên lesson Giá trị trả về, dòng 2 là trạng thái Hoàn thành. Học sinh nên dùng 2 lệnh print() khác nhau và không gộp chung thành một dòng. Kết quả cần khớp chính xác: Giá trị trả về\nHoàn thành.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'print("Giá trị trả về")\nprint("Hoàn thành")', '[{"input": "", "expected_output": "Giá trị trả về\nHoàn thành"}]'::jsonb, 'Cơ bản'),
('Giá trị trả về - Thứ tự bài học', 'Nhiệm vụ: tạo biến số nguyên lưu thứ tự của lesson Giá trị trả về, chuyển số đó sang chuỗi khi cần ghép với câu thông báo, rồi in ra màn hình. Học sinh cần chú ý dùng str() khi nối số với chuỗi. Kết quả cần khớp chính xác: Thứ tự lesson: 16.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'lesson_order = 16\nprint("Thứ tự lesson: " + str(lesson_order))', '[{"input": "", "expected_output": "Thứ tự lesson: 16"}]'::jsonb, 'Cơ bản'),
('Giá trị trả về - Hàm thông điệp', 'Nhiệm vụ: viết một hàm không có tham số để trả về thông điệp học tập của lesson Giá trị trả về, sau đó gọi hàm và in giá trị trả về. Học sinh cần luyện cú pháp def, return và cách gọi hàm trong Python. Kết quả cần khớp chính xác: Sẵn sàng học Giá trị trả về.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'def message():\n    return "Sẵn sàng học Giá trị trả về"\nprint(message())', '[{"input": "", "expected_output": "Sẵn sàng học Giá trị trả về"}]'::jsonb, 'Cơ bản'),
('Giá trị trả về - Ba bước luyện tập', 'Nhiệm vụ: dùng vòng lặp để in ra 3 bước luyện tập theo thứ tự từ 1 đến 3. Học sinh cần sử dụng range(), biến lặp và str() để tạo từng dòng theo mẫu Bước 1, Bước 2, Bước 3. Kết quả cần khớp chính xác: Bước 1\nBước 2\nBước 3.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'for step in range(1, 4):\n    print("Bước " + str(step))', '[{"input": "", "expected_output": "Bước 1\nBước 2\nBước 3"}]'::jsonb, 'Cơ bản'),
('Giá trị trả về - Từ điển bài học', 'Nhiệm vụ: tạo một dictionary lưu thông tin lesson gồm tên bài học và số thứ tự, sau đó lấy dữ liệu từ dictionary để in theo định dạng tên: số. Học sinh cần luyện cách tạo dictionary, truy cập giá trị bằng key và chuyển số sang chuỗi khi ghép. Kết quả cần khớp chính xác: Giá trị trả về: 16.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'lesson = {"name": "Giá trị trả về", "order": 16}\nprint(lesson["name"] + ": " + str(lesson["order"]))', '[{"input": "", "expected_output": "Giá trị trả về: 16"}]'::jsonb, 'Cơ bản'),
('Giá trị trả về - Tổng kết thử thách', 'Nhiệm vụ: in phần tổng kết của lesson Giá trị trả về. Dòng đầu là tên lesson, các dòng sau lần lượt thể hiện số lượng challenge Easy, Medium và Hard. Học sinh nên tạo danh sách các dòng tổng kết rồi dùng vòng lặp để in từng dòng. Kết quả cần khớp chính xác: Giá trị trả về\nEasy: 3\nMedium: 3\nHard: 4.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'levels = ["Easy: 3", "Medium: 3", "Hard: 4"]\nprint("Giá trị trả về")\nfor level in levels:\n    print(level)', '[{"input": "", "expected_output": "Giá trị trả về\nEasy: 3\nMedium: 3\nHard: 4"}]'::jsonb, 'Cơ bản');
INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Tham số hàm - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Tham số hàm. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Tham số hàm.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Tham số hàm")', '[{"input": "", "expected_output": "Tham số hàm"}]'::jsonb, 'Cơ bản'),
