INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Thêm phần tử vào list - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Thêm phần tử vào list. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Thêm phần tử vào list.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Thêm phần tử vào list")', '[{"input": "", "expected_output": "Thêm phần tử vào list"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Gọi tên chủ đề', 'Nhiệm vụ: in ra mã chủ đề của lesson Thêm phần tử vào list. Học sinh cần quan sát chuỗi yêu cầu và dùng print() để hiển thị đúng nội dung, giữ nguyên chữ thường, dấu gạch ngang và khoảng trắng nếu có. Kết quả cần khớp chính xác: lists-update.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("lists-update")', '[{"input": "", "expected_output": "lists-update"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Thông tin bài học', 'Nhiệm vụ: hiển thị dòng giới thiệu bài học. Học sinh cần dùng print() để in đúng định dạng gồm chữ Bài, số thứ tự và tên lesson Thêm phần tử vào list. Không thêm ký tự khác ở đầu hoặc cuối dòng. Kết quả cần khớp chính xác: Bài 19: Thêm phần tử vào list.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Bài 19: Thêm phần tử vào list")', '[{"input": "", "expected_output": "Bài 19: Thêm phần tử vào list"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Biến chủ đề', 'Nhiệm vụ: tạo một biến lưu tên chủ đề Thêm phần tử vào list, sau đó ghép chuỗi với phần '' - luyện tập'' và in ra màn hình. Học sinh cần luyện cách khai báo biến, nối chuỗi bằng toán tử + và dùng print() để xuất kết quả. Kết quả cần khớp chính xác: Thêm phần tử vào list - luyện tập.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'topic = "Thêm phần tử vào list"\nprint(topic + " - luyện tập")', '[{"input": "", "expected_output": "Thêm phần tử vào list - luyện tập"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Hai dòng kết quả', 'Nhiệm vụ: in kết quả trên 2 dòng riêng biệt. Dòng 1 là tên lesson Thêm phần tử vào list, dòng 2 là trạng thái Hoàn thành. Học sinh nên dùng 2 lệnh print() khác nhau và không gộp chung thành một dòng. Kết quả cần khớp chính xác: Thêm phần tử vào list\nHoàn thành.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'print("Thêm phần tử vào list")\nprint("Hoàn thành")', '[{"input": "", "expected_output": "Thêm phần tử vào list\nHoàn thành"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Thứ tự bài học', 'Nhiệm vụ: tạo biến số nguyên lưu thứ tự của lesson Thêm phần tử vào list, chuyển số đó sang chuỗi khi cần ghép với câu thông báo, rồi in ra màn hình. Học sinh cần chú ý dùng str() khi nối số với chuỗi. Kết quả cần khớp chính xác: Thứ tự lesson: 19.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'lesson_order = 19\nprint("Thứ tự lesson: " + str(lesson_order))', '[{"input": "", "expected_output": "Thứ tự lesson: 19"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Hàm thông điệp', 'Nhiệm vụ: viết một hàm không có tham số để trả về thông điệp học tập của lesson Thêm phần tử vào list, sau đó gọi hàm và in giá trị trả về. Học sinh cần luyện cú pháp def, return và cách gọi hàm trong Python. Kết quả cần khớp chính xác: Sẵn sàng học Thêm phần tử vào list.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'def message():\n    return "Sẵn sàng học Thêm phần tử vào list"\nprint(message())', '[{"input": "", "expected_output": "Sẵn sàng học Thêm phần tử vào list"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Ba bước luyện tập', 'Nhiệm vụ: dùng vòng lặp để in ra 3 bước luyện tập theo thứ tự từ 1 đến 3. Học sinh cần sử dụng range(), biến lặp và str() để tạo từng dòng theo mẫu Bước 1, Bước 2, Bước 3. Kết quả cần khớp chính xác: Bước 1\nBước 2\nBước 3.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'for step in range(1, 4):\n    print("Bước " + str(step))', '[{"input": "", "expected_output": "Bước 1\nBước 2\nBước 3"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Từ điển bài học', 'Nhiệm vụ: tạo một dictionary lưu thông tin lesson gồm tên bài học và số thứ tự, sau đó lấy dữ liệu từ dictionary để in theo định dạng tên: số. Học sinh cần luyện cách tạo dictionary, truy cập giá trị bằng key và chuyển số sang chuỗi khi ghép. Kết quả cần khớp chính xác: Thêm phần tử vào list: 19.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'lesson = {"name": "Thêm phần tử vào list", "order": 19}\nprint(lesson["name"] + ": " + str(lesson["order"]))', '[{"input": "", "expected_output": "Thêm phần tử vào list: 19"}]'::jsonb, 'Cơ bản'),
('Thêm phần tử vào list - Tổng kết thử thách', 'Nhiệm vụ: in phần tổng kết của lesson Thêm phần tử vào list. Dòng đầu là tên lesson, các dòng sau lần lượt thể hiện số lượng challenge Easy, Medium và Hard. Học sinh nên tạo danh sách các dòng tổng kết rồi dùng vòng lặp để in từng dòng. Kết quả cần khớp chính xác: Thêm phần tử vào list\nEasy: 3\nMedium: 3\nHard: 4.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'levels = ["Easy: 3", "Medium: 3", "Hard: 4"]\nprint("Thêm phần tử vào list")\nfor level in levels:\n    print(level)', '[{"input": "", "expected_output": "Thêm phần tử vào list\nEasy: 3\nMedium: 3\nHard: 4"}]'::jsonb, 'Cơ bản');
INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Cắt danh sách - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Cắt danh sách. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Cắt danh sách.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Cắt danh sách")', '[{"input": "", "expected_output": "Cắt danh sách"}]'::jsonb, 'Cơ bản'),
