INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Phương thức chuỗi - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Phương thức chuỗi. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Phương thức chuỗi.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Phương thức chuỗi")', '[{"input": "", "expected_output": "Phương thức chuỗi"}]'::jsonb, 'Nâng cao'),
('Phương thức chuỗi - Gọi tên chủ đề', 'Nhiệm vụ: in ra mã chủ đề của lesson Phương thức chuỗi. Học sinh cần quan sát chuỗi yêu cầu và dùng print() để hiển thị đúng nội dung, giữ nguyên chữ thường, dấu gạch ngang và khoảng trắng nếu có. Kết quả cần khớp chính xác: strings-methods.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("strings-methods")', '[{"input": "", "expected_output": "strings-methods"}]'::jsonb, 'Nâng cao'),
