INSERT INTO challenges (title, description, difficulty, xp_reward, coins_reward, starter_code, solution_code, test_cases, track) VALUES
('Dữ liệu lồng nhau - Khởi động', 'Nhiệm vụ: viết chương trình Python đầu tiên cho chủ đề Dữ liệu lồng nhau. Học sinh cần dùng lệnh print() để in đúng tên bài học ra màn hình. Không cần nhập dữ liệu từ bàn phím. Kết quả cần khớp chính xác: Dữ liệu lồng nhau.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Dữ liệu lồng nhau")', '[{"input": "", "expected_output": "Dữ liệu lồng nhau"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Gọi tên chủ đề', 'Nhiệm vụ: in ra mã chủ đề của lesson Dữ liệu lồng nhau. Học sinh cần quan sát chuỗi yêu cầu và dùng print() để hiển thị đúng nội dung, giữ nguyên chữ thường, dấu gạch ngang và khoảng trắng nếu có. Kết quả cần khớp chính xác: nested-data.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("nested-data")', '[{"input": "", "expected_output": "nested-data"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Thông tin bài học', 'Nhiệm vụ: hiển thị dòng giới thiệu bài học. Học sinh cần dùng print() để in đúng định dạng gồm chữ Bài, số thứ tự và tên lesson Dữ liệu lồng nhau. Không thêm ký tự khác ở đầu hoặc cuối dòng. Kết quả cần khớp chính xác: Bài 24: Dữ liệu lồng nhau.', 'easy', 10, 20, E'# Hãy viết mã của bạn bên dưới\n', E'print("Bài 24: Dữ liệu lồng nhau")', '[{"input": "", "expected_output": "Bài 24: Dữ liệu lồng nhau"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Biến chủ đề', 'Nhiệm vụ: tạo một biến lưu tên chủ đề Dữ liệu lồng nhau, sau đó ghép chuỗi với phần '' - luyện tập'' và in ra màn hình. Học sinh cần luyện cách khai báo biến, nối chuỗi bằng toán tử + và dùng print() để xuất kết quả. Kết quả cần khớp chính xác: Dữ liệu lồng nhau - luyện tập.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'topic = "Dữ liệu lồng nhau"\nprint(topic + " - luyện tập")', '[{"input": "", "expected_output": "Dữ liệu lồng nhau - luyện tập"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Hai dòng kết quả', 'Nhiệm vụ: in kết quả trên 2 dòng riêng biệt. Dòng 1 là tên lesson Dữ liệu lồng nhau, dòng 2 là trạng thái Hoàn thành. Học sinh nên dùng 2 lệnh print() khác nhau và không gộp chung thành một dòng. Kết quả cần khớp chính xác: Dữ liệu lồng nhau\nHoàn thành.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'print("Dữ liệu lồng nhau")\nprint("Hoàn thành")', '[{"input": "", "expected_output": "Dữ liệu lồng nhau\nHoàn thành"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Thứ tự bài học', 'Nhiệm vụ: tạo biến số nguyên lưu thứ tự của lesson Dữ liệu lồng nhau, chuyển số đó sang chuỗi khi cần ghép với câu thông báo, rồi in ra màn hình. Học sinh cần chú ý dùng str() khi nối số với chuỗi. Kết quả cần khớp chính xác: Thứ tự lesson: 24.', 'medium', 20, 40, E'# Hãy viết mã của bạn bên dưới\n', E'lesson_order = 24\nprint("Thứ tự lesson: " + str(lesson_order))', '[{"input": "", "expected_output": "Thứ tự lesson: 24"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Hàm thông điệp', 'Nhiệm vụ: viết một hàm không có tham số để trả về thông điệp học tập của lesson Dữ liệu lồng nhau, sau đó gọi hàm và in giá trị trả về. Học sinh cần luyện cú pháp def, return và cách gọi hàm trong Python. Kết quả cần khớp chính xác: Sẵn sàng học Dữ liệu lồng nhau.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'def message():\n    return "Sẵn sàng học Dữ liệu lồng nhau"\nprint(message())', '[{"input": "", "expected_output": "Sẵn sàng học Dữ liệu lồng nhau"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Ba bước luyện tập', 'Nhiệm vụ: dùng vòng lặp để in ra 3 bước luyện tập theo thứ tự từ 1 đến 3. Học sinh cần sử dụng range(), biến lặp và str() để tạo từng dòng theo mẫu Bước 1, Bước 2, Bước 3. Kết quả cần khớp chính xác: Bước 1\nBước 2\nBước 3.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'for step in range(1, 4):\n    print("Bước " + str(step))', '[{"input": "", "expected_output": "Bước 1\nBước 2\nBước 3"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Từ điển bài học', 'Nhiệm vụ: tạo một dictionary lưu thông tin lesson gồm tên bài học và số thứ tự, sau đó lấy dữ liệu từ dictionary để in theo định dạng tên: số. Học sinh cần luyện cách tạo dictionary, truy cập giá trị bằng key và chuyển số sang chuỗi khi ghép. Kết quả cần khớp chính xác: Dữ liệu lồng nhau: 24.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'lesson = {"name": "Dữ liệu lồng nhau", "order": 24}\nprint(lesson["name"] + ": " + str(lesson["order"]))', '[{"input": "", "expected_output": "Dữ liệu lồng nhau: 24"}]'::jsonb, 'Nâng cao'),
('Dữ liệu lồng nhau - Tổng kết thử thách', 'Nhiệm vụ: in phần tổng kết của lesson Dữ liệu lồng nhau. Dòng đầu là tên lesson, các dòng sau lần lượt thể hiện số lượng challenge Easy, Medium và Hard. Học sinh nên tạo danh sách các dòng tổng kết rồi dùng vòng lặp để in từng dòng. Kết quả cần khớp chính xác: Dữ liệu lồng nhau\nEasy: 3\nMedium: 3\nHard: 4.', 'hard', 30, 60, E'# Hãy viết mã của bạn bên dưới\n', E'levels = ["Easy: 3", "Medium: 3", "Hard: 4"]\nprint("Dữ liệu lồng nhau")\nfor level in levels:\n    print(level)', '[{"input": "", "expected_output": "Dữ liệu lồng nhau\nEasy: 3\nMedium: 3\nHard: 4"}]'::jsonb, 'Nâng cao');
